package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithTrim() {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat trimmed = original.withTrim();

        assertNotNull(trimmed);
        assertTrue(trimmed.getTrim());
        // Ensure original is unchanged (immutable pattern)
        assertFalse(original.getTrim());

        // Also test withTrim(false) to ensure difference
        CSVFormat notTrimmed = original.withTrim(false);
        assertNotNull(notTrimmed);
        assertFalse(notTrimmed.getTrim());
    }
}
